def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            if ratio < 0.05 * j:
                score += (10 - j) * np.exp(-ratio * j * 2) + np.cos(ratio * np.pi * j)
            elif 0.05 * j <= ratio < 0.3:
                score += (j ** 3) * np.sin(ratio * np.pi * j / 2) - np.log1p(j * ratio)
            else:
                score += np.log1p(ratio * j) * (j / 3) + np.sqrt(j * ratio)
        if capacity - item < 0.03 * capacity:
            score *= 2.5
            for m in range(1, 5):
                if (capacity - item) / capacity < 0.01 * m:
                    score += m * np.tanh(item / (capacity + 1e-9)) * 3
        elif capacity - item < 0.15 * capacity:
            score *= 1.5
            for n in range(1, 3):
                if (capacity - item) / capacity > 0.05 * n:
                    score += np.log1p(n * ratio) * n
        else:
            for k in range(1, 6):
                if (capacity - item) / capacity > 0.2 * k:
                    score += np.sqrt(k * ratio) + np.sin(k * ratio * np.pi / 4)
        if item > 0.7 * capacity:
            score += np.tanh(item / capacity) * 7 + np.exp(-ratio)
        if score < 0:
            score = abs(score) * 0.7 + 1
        if np.isnan(score) or np.isinf(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    return priorities
